#include <fstream>
#include <iostream>
using namespace std;

int main() {
 ofstream outFile("data.txt"); // Create output file

 if(outFile.is_open()) {
 outFile << "Hello, World!" << endl;
 outFile << "File Handling in C++" << endl;
 outFile << 100 << endl;
 outFile.close(); // Close the file
 cout << "File written successfully!" << endl;
 } else {
 cout << "Error: Could not open file!" << endl;
 }
 return 0;
}

#include <fstream>
#include <iostream>
#include <string>
using namespace std;

int main() {
 ifstream inFile("data.txt");
 string line;

 if(inFile.is_open()) {
 while(getline(inFile, line)) {
 cout << line << endl;
 }
 inFile.close();
 } else {
 cout << "Error: Could not open file!" << endl;
 }
 return 0;
}

#include <fstream>
#include <iostream>
using namespace std;

int main() {
 ofstream appFile("log.txt", ios::app); // Open in append mode

 if(appFile.is_open()) {
 appFile << "Log entry 1: Program started" << endl;
 appFile << "Log entry 2: Processing data" << endl;
 appFile.close();
 cout << "Data appended successfully!" << endl;
 }
 return 0;
}

#include <fstream>
#include <iostream>
using namespace std;

int main() {
 ifstream inFile("data.txt");
 string word;

 if(inFile.is_open()) {
 while(inFile >> word) { // Reads until whitespace
 cout << word << endl;
 }
 inFile.close();
 }
 return 0;
}

#include <fstream>
#include <iostream>
using namespace std;

int main() {
 fstream file("data.txt", ios::in | ios::out);

 if(file.is_open()) {
 // Write some data
 file << "Hello ";

 // Seek to beginning
 file.seekg(0);

 // Read the data
 string data;
 file >> data;
 cout << "Read: " << data << endl;

 file.close();
 }
 return 0;
}

#include <fstream>
#include <iostream>
using namespace std;

int main() {
 ifstream source("source.txt");
 ofstream dest("destination.txt");
 string line;

 if(source.is_open() && dest.is_open()) {
 while(getline(source, line)) {
 dest << line << endl;
 }
 source.close();
 dest.close();
 cout << "File copied successfully!" << endl;
 } else {
 cout << "Error opening files!" << endl;
 }
 return 0;
}
